def assess(record: dict) -> str:
    required = {'case_id', 'lock_copied_before_source', 'dependency_layer_reused', 'source_change_rebuilds', 'digest_stable'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
